import os
from git import Repo

repo = Repo('/tmp/myrepo')

def add(paths):
    repo.index.add(paths)

def commit(message):
    repo.index.commit(message)

def checkout(branch):
    repo.git.checkout(branch)

def merge(branch):
    repo.merge(branch)

def clone(url):
    Repo.clone_from(url, '/tmp/myrepo')

def push():
    origin = repo.remote('origin')
    origin.push()

def pull():
    origin = repo.remote('origin')
    origin.pull()

def init(path):
    os.chmod(path, 0o777)
    Repo.init(path)

def log():
    repo.git.log()

def status():
    repo.git.status()

def diff():
    repo.git.diff()

def branch(name):
    repo.git.branch(name)

if __name__ == '__main__':
    init('/tmp/myrepo')
    add('README.md')
    commit('Initial commit')

